css:
.wrapper.rt-topreps {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --subtle: var(--color-gray-700, #C2C2CC);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --hairline: rgba(255,255,255,.06);
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  container-type: inline-size;
  height: 100%;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}
.wrapper.rt-topreps .chart-card,
.wrapper.rt-topreps .head,
.wrapper.rt-topreps .canvas,
.wrapper.rt-topreps .empty { box-sizing: border-box; }

.wrapper.rt-topreps .chart-card {
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  min-height: 480px;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .16s ease, box-shadow .16s ease;
}
.wrapper.rt-topreps .chart-card:hover {
  border-color: color-mix(in srgb, var(--accent) 32%, var(--line));
}

.wrapper.rt-topreps .head {
  display: flex;
  flex-direction: column;
  gap: 3px;
  min-width: 0;
  padding-bottom: 12px;
  margin-bottom: 14px;
  border-bottom: 1px solid var(--hairline);
}
.wrapper.rt-topreps .head h3 {
  margin: 0;
  display: flex;
  align-items: center;
  min-width: 0;
  font: 800 14px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  color: var(--ink);
  overflow-wrap: anywhere;
}
.wrapper.rt-topreps .head h3::before {
  content: "";
  flex: 0 0 auto;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  margin-right: 9px;
  background: var(--accent);
  box-shadow: 0 0 7px -1px color-mix(in srgb, var(--accent) 65%, transparent);
}
.wrapper.rt-topreps .head .sub {
  display: block;
  margin: 0;
  padding-left: 17px;
  font: 600 11px/1.35 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .04em;
  color: var(--muted);
  overflow-wrap: anywhere;
}

.wrapper.rt-topreps .canvas {
  flex: 1 1 auto;
  width: 100%;
  max-width: 100%;
  min-width: 0;
  min-height: 440px;
}
.wrapper.rt-topreps .empty {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  width: 100%;
  min-height: 200px;
  padding: 24px;
  text-align: center;
  color: var(--muted);
  font: 600 13px/1.45 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

@container (max-width: 720px) {
  .wrapper.rt-topreps .chart-card { padding: 15px 16px; min-height: 460px; }
  .wrapper.rt-topreps .canvas { min-height: 420px; }
}
@container (max-width: 520px) {
  .wrapper.rt-topreps .chart-card { padding: 13px 14px; min-height: 440px; }
  .wrapper.rt-topreps .canvas { min-height: 400px; }
  .wrapper.rt-topreps .head { margin-bottom: 12px; padding-bottom: 10px; }
}
@container (max-width: 380px) {
  .wrapper.rt-topreps .chart-card { padding: 12px 12px; min-height: 420px; }
  .wrapper.rt-topreps .canvas { min-height: 380px; }
}
@supports not (container-type: inline-size) {
  @media (max-width: 720px) {
    .wrapper.rt-topreps .chart-card { padding: 15px 16px; min-height: 460px; }
    .wrapper.rt-topreps .canvas { min-height: 420px; }
  }
  @media (max-width: 520px) {
    .wrapper.rt-topreps .chart-card { padding: 13px 14px; min-height: 440px; }
    .wrapper.rt-topreps .canvas { min-height: 400px; }
  }
}
@media (prefers-reduced-motion: reduce) {
  .wrapper.rt-topreps .chart-card { transition: none; }
}
